import React, { Component } from 'react';
import { Col } from 'react-bootstrap';
// import ReactDOM from 'react-dom';
import './Links.css';
// import '../debug.css';
// import eu from '../../imgs/eu.jpg'

// primeiro componente do corpo da página a aparecer
class Links extends Component {
	
	// função para fazer o scroll para determinado elemento sem alterar a URL
	scrollTo(elementId) {
		var element = document.getElementById(elementId);
		if (element != null)
			element.scrollIntoView({ 
				block: 'start',
				behavior: 'smooth' 
			});
		else
			console.log("%cErro:",  "color: red; font-weight: bold;", "elemento \"" + elementId + "\" não encontrado");
		
		
	}

	render() {
		return(
			<div>
				<Col className="center links">
					<p>
						<span onClick={() => {this.scrollTo('about')} }>sobre mim</span> | <span onClick={() => {this.scrollTo('projects')} }>projetos</span> | <span onClick={() => {this.scrollTo('contact')} }>contato</span> | <span onClick={() => {this.scrollTo('miscellaneous')} }>diversos</span> 
					</p>
				</Col>
			</div>
		);
	}
}

export default Links;
